WHERE project_id = #{projectId}
  AND file_category = #{fileCategory}
  AND deleted = 0
ORDER BY upload_time DESC

SELECT 
FROM file_upload_records

    deleted = 0

        AND project_id = #{projectId}


        AND file_category = #{fileCategory}


        AND upload_status = #{uploadStatus}


        AND process_status = #{processStatus}


